# Terraform：将完整数据包的默认无状态操作设置为丢弃
resource "aws_networkfirewall_firewall_policy" "<example_resource_name>" {
  name = "<example_resource_name>"

  firewall_policy {
    stateless_default_actions          = ["aws:drop"]  # 关键：完整数据包默认设置为丢弃（修复检查）
    stateless_fragment_default_actions = ["aws:drop"]  # 有效策略所需
  }
}
